            writer.WriteNumber("id", fileResponse.Id);

            writer.WriteString("filename", fileResponse.Filename);

            writer.WriteString("file_path", fileResponse.FilePath);

            writer.WriteString("file_type", fileResponse.FileType);

            writer.WriteNumber("file_size", fileResponse.FileSize);

            writer.WriteNumber("print_count", fileResponse.PrintCount);

            writer.WriteString("created_at", fileResponse.CreatedAt.ToString(CreatedAtFormat));

            writer.WriteString("updated_at", fileResponse.UpdatedAt.ToString(UpdatedAtFormat));

            if (fileResponse.FolderId != null)
                writer.WriteNumber("folder_id", fileResponse.FolderId.Value);
            else
                writer.WriteNull("folder_id");

            if (fileResponse.FolderNameOption.IsSet)
                if (fileResponse.FolderNameOption.Value != null)
                    writer.WriteString("folder_name", fileResponse.FolderName);
                else
                    writer.WriteNull("folder_name");

            if (fileResponse.ProjectId != null)
                writer.WriteNumber("project_id", fileResponse.ProjectId.Value);
            else
                writer.WriteNull("project_id");

            if (fileResponse.ProjectNameOption.IsSet)
                if (fileResponse.ProjectNameOption.Value != null)
                    writer.WriteString("project_name", fileResponse.ProjectName);
                else
                    writer.WriteNull("project_name");

            if (fileResponse.IsExternalOption.IsSet)
                writer.WriteBoolean("is_external", fileResponse.IsExternalOption.Value!.Value);

            if (fileResponse.FileHash != null)
                writer.WriteString("file_hash", fileResponse.FileHash);
            else
                writer.WriteNull("file_hash");

            if (fileResponse.ThumbnailPath != null)
                writer.WriteString("thumbnail_path", fileResponse.ThumbnailPath);
            else
                writer.WriteNull("thumbnail_path");

            if (fileResponse.Metadata != null)
            {
                writer.WritePropertyName("metadata");
                JsonSerializer.Serialize(writer, fileResponse.Metadata, jsonSerializerOptions);
            }
            else
                writer.WriteNull("metadata");
            if (fileResponse.LastPrintedAt != null)
                writer.WriteString("last_printed_at", fileResponse.LastPrintedAt.Value.ToString(LastPrintedAtFormat));
            else
                writer.WriteNull("last_printed_at");

            if (fileResponse.Notes != null)
                writer.WriteString("notes", fileResponse.Notes);
            else
                writer.WriteNull("notes");

            if (fileResponse.DuplicatesOption.IsSet)
                if (fileResponse.DuplicatesOption.Value != null)
                {
                    writer.WritePropertyName("duplicates");
                    JsonSerializer.Serialize(writer, fileResponse.Duplicates, jsonSerializerOptions);
                }
                else
                    writer.WriteNull("duplicates");
            if (fileResponse.DuplicateCountOption.IsSet)
                writer.WriteNumber("duplicate_count", fileResponse.DuplicateCountOption.Value!.Value);

            if (fileResponse.CreatedByIdOption.IsSet)
                if (fileResponse.CreatedByIdOption.Value != null)
                    writer.WriteNumber("created_by_id", fileResponse.CreatedByIdOption.Value!.Value);
                else
                    writer.WriteNull("created_by_id");

            if (fileResponse.CreatedByUsernameOption.IsSet)
                if (fileResponse.CreatedByUsernameOption.Value != null)
                    writer.WriteString("created_by_username", fileResponse.CreatedByUsername);
                else
                    writer.WriteNull("created_by_username");

            if (fileResponse.PrintNameOption.IsSet)
                if (fileResponse.PrintNameOption.Value != null)
                    writer.WriteString("print_name", fileResponse.PrintName);
                else
                    writer.WriteNull("print_name");

            if (fileResponse.PrintTimeSecondsOption.IsSet)
                if (fileResponse.PrintTimeSecondsOption.Value != null)
                    writer.WriteNumber("print_time_seconds", fileResponse.PrintTimeSecondsOption.Value!.Value);
                else
                    writer.WriteNull("print_time_seconds");

            if (fileResponse.FilamentUsedGramsOption.IsSet)
                if (fileResponse.FilamentUsedGramsOption.Value != null)
                    writer.WriteNumber("filament_used_grams", fileResponse.FilamentUsedGramsOption.Value!.Value);
                else
                    writer.WriteNull("filament_used_grams");

            if (fileResponse.SlicedForModelOption.IsSet)
                if (fileResponse.SlicedForModelOption.Value != null)
                    writer.WriteString("sliced_for_model", fileResponse.SlicedForModel);
                else
                    writer.WriteNull("sliced_for_model");
        }
    }
